# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import json
import pymysql
import os
from typing import Dict, Any, List

def lambda_handler(event: Dict[str, Any], context: Any) -> Dict[str, Any]:
    # Database connection parameters
    db_config = {
        'host': os.environ['DB_HOST'],
        'user': os.environ['DB_USER'],
        'password': os.environ['DB_PASSWORD'],
        'database': os.environ['DB_NAME'],
        'port': int(os.environ.get('DB_PORT', 3306)),
        'charset': 'utf8mb4'
    }
    
    # Parse query parameters
    query_params = event.get('queryStringParameters', {})
    
    # Build dynamic SQL query
    base_query = "SELECT * FROM products WHERE 1=1"
    params = []
    
    # Add filters based on query parameters
    if query_params.get('name'):
        base_query += " AND name LIKE %s"
        params.append(f"%{query_params['name']}%")
    
    if query_params.get('category'):
        base_query += " AND category = %s"
        params.append(query_params['category'])
    
    if query_params.get('min_price'):
        base_query += " AND price >= %s"
        params.append(float(query_params['min_price']))
    
    if query_params.get('max_price'):
        base_query += " AND price <= %s"
        params.append(float(query_params['max_price']))
    
    if query_params.get('brand'):
        base_query += " AND brand = %s"
        params.append(query_params['brand'])
    
    # Add sorting
    sort_by = query_params.get('sort_by', 'name')
    sort_order = query_params.get('sort_order', 'ASC')
    
    if sort_by in ['name', 'price', 'category', 'brand']:
        base_query += f" ORDER BY {sort_by} {sort_order}"
    
    # Add pagination
    page = int(query_params.get('page', 1))
    page_size = int(query_params.get('page_size', 10))
    offset = (page - 1) * page_size
    
    base_query += " LIMIT %s OFFSET %s"
    params.extend([page_size, offset])
    
    try:
        # Connect to database
        connection = pymysql.connect(**db_config)
        
        with connection.cursor(pymysql.cursors.DictCursor) as cursor:
            cursor.execute(base_query, params)
            results = cursor.fetchall()
            
            # Get total count for pagination info
            count_query = "SELECT COUNT(*) as total FROM products WHERE 1=1"
            count_params = []
            
            # Rebuild count query with same filters
            if query_params.get('name'):
                count_query += " AND name LIKE %s"
                count_params.append(f"%{query_params['name']}%")
            
            if query_params.get('category'):
                count_query += " AND category = %s"
                count_params.append(query_params['category'])
            
            if query_params.get('min_price'):
                count_query += " AND price >= %s"
                count_params.append(float(query_params['min_price']))
            
            if query_params.get('max_price'):
                count_query += " AND price <= %s"
                count_params.append(float(query_params['max_price']))
            
            if query_params.get('brand'):
                count_query += " AND brand = %s"
                count_params.append(query_params['brand'])
            
            cursor.execute(count_query, count_params)
            total_count = cursor.fetchone()['total']
            
        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'products': results,
                'pagination': {
                    'page': page,
                    'page_size': page_size,
                    'total': total_count,
                    'pages': (total_count + page_size - 1) // page_size
                }
            })
        }
        
    except Exception as e:
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json',
                'Access-Control-Allow-Origin': '*'
            },
            'body': json.dumps({
                'error': str(e)
            })
        }
    finally:
        if 'connection' in locals():
            connection.close()